                        )}
                      </div>

                      <div className="w-[320px] border border-slate-200 rounded-[10px] p-4 text-[#1a2b5e] bg-slate-50/40">
                        <h2 className="text-sm font-black mb-1.5 uppercase tracking-wide">Client: {client?.name}</h2>
