                              <td className="py-4 px-4 text-lg font-black text-white bg-[#1a2b5e] text-right text-nowrap rounded-br-xl">{invoice.grandTotal.toLocaleString('fr-FR', { minimumFractionDigits: 2 })} MAD</td>
                            </tr>
