            </button>
            <button onClick={onClose} className="px-4 py-2 bg-slate-100 rounded-lg font-bold text-[10px] uppercase tracking-widest text-slate-400 hover:bg-slate-200 transition-colors">
              Fermer
            </button>
          </div>
        </div>

        {/* Zone de prévisualisation */}
