                    <button onClick={() => onEditInvoice(invoice.id)} className="w-8 h-8 rounded-lg text-slate-400 hover:bg-blue-50 dark:hover:bg-blue-500/10 hover:text-blue-600 transition-all"><i className="fas fa-edit text-xs"></i></button>
                    <button onClick={() => onAddPayment(invoice.id)} className="w-8 h-8 rounded-lg text-slate-400 hover:bg-emerald-50 dark:hover:bg-emerald-500/10 hover:text-emerald-600 transition-all"><i className="fas fa-money-bill-wave text-xs"></i></button>
                    <button onClick={() => onPdfInvoice(invoice.id)} className="w-8 h-8 rounded-lg text-slate-400 hover:bg-amber-50 dark:hover:bg-amber-500/10 hover:text-amber-600 transition-all"><i className="fas fa-file-pdf text-xs"></i></button>
                    <button onClick={() => onDeleteInvoice(invoice.id)} className="w-8 h-8 rounded-lg text-slate-400 hover:bg-rose-50 dark:hover:bg-rose-500/10 hover:text-rose-600 transition-all"><i className="fas fa-trash-alt text-xs"></i></button>
                  </div>
                </td>
