            )}
          </tbody>
        </table>
      </div>

      {/* Pagination Footer */}
      <div className="px-6 py-4 bg-slate-50 dark:bg-slate-900/60 border-t border-slate-100 dark:border-white/5 flex flex-col sm:flex-row items-center justify-between gap-4 shrink-0">
        <div className="flex flex-col sm:flex-row items-center gap-4 sm:gap-8">
          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest whitespace-nowrap">
            Affichage de <span className="text-slate-800 dark:text-slate-200">{(currentPage - 1) * itemsPerPage + 1}</span> à <span className="text-slate-800 dark:text-slate-200">{Math.min(currentPage * itemsPerPage, filteredAndSortedInvoices.length)}</span> sur <span className="text-indigo-600 dark:text-indigo-400 font-black">{filteredAndSortedInvoices.length}</span> documents
          </div>
          <div className="flex items-center space-x-2">
            <label className="text-[9px] font-black uppercase text-slate-400 tracking-tighter whitespace-nowrap">Lignes par page:</label>
            <select value={itemsPerPage} onChange={(e) => setItemsPerPage(Number(e.target.value))} className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-white/10 rounded-lg text-[10px] font-black px-2 py-1 outline-none dark:text-white">
              {pageSizeOptions.map(option => <option key={option} value={option}>{option}</option>)}
            </select>
          </div>
        </div>

        {totalPages > 1 && (
          <div className="flex items-center space-x-1">
            <button onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} className="w-8 h-8 rounded-lg flex items-center justify-center border border-slate-200 dark:border-white/10 text-slate-400 disabled:opacity-30 hover:bg-white dark:hover:bg-slate-800 transition-all"><i className="fas fa-chevron-left text-[10px]"></i></button>
            <div className="flex items-center space-x-1">
              {[...Array(totalPages)].map((_, i) => (
                <button key={i} onClick={() => setCurrentPage(i + 1)} className={`w-8 h-8 rounded-lg text-[10px] font-black transition-all ${currentPage === i + 1 ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800'}`}>{i + 1}</button>
              ))}
            </div>
            <button onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages} className="w-8 h-8 rounded-lg flex items-center justify-center border border-slate-200 dark:border-white/10 text-slate-400 disabled:opacity-30 hover:bg-white dark:hover:bg-slate-800 transition-all"><i className="fas fa-chevron-right text-[10px]"></i></button>
          </div>
        )}
      </div>
    </div>
  );
};

