import React, { useState } from 'react';
import { Client, Invoice } from '../types';

interface ClientListProps {
  clients: Client[];
  invoices: Invoice[];
  onEditClient: (id: string) => void;
  onDeleteClient: (id: string) => void;
  onViewHistory: (id: string) => void;
  onAddClient: () => void;
}

const ClientList: React.FC<ClientListProps> = ({ clients, invoices, onEditClient, onDeleteClient, onViewHistory, onAddClient }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const getClientStats = (clientId: string) => {
    const clientInvoices = invoices.filter(inv => inv.clientId === clientId);
    const totalTransactions = clientInvoices.reduce((sum, inv) => sum + inv.grandTotal, 0);
    const totalPaid = clientInvoices.reduce((sum, inv) => {
      const paymentsSum = (inv.payments || []).reduce((pSum, p) => pSum + p.amount, 0);
      return sum + paymentsSum;
    }, 0);
    return {
      totalTransactions,
      remaining: totalTransactions - totalPaid,
      invoiceCount: clientInvoices.length
    };
  };

  const filteredClients = clients.filter(client => {
    const stats = getClientStats(client.id);
    const hasActivity = stats.invoiceCount > 0;
    if (!hasActivity && !searchTerm) return false;
    return client.name.toLowerCase().includes(searchTerm.toLowerCase());
  });

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-xl font-black text-slate-800 dark:text-white uppercase tracking-tight">Portefeuille Clients</h3>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Gérez vos relations commerciales et soldes clients</p>
        </div>
        <button 
          onClick={onAddClient}
          className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl text-[11px] font-black uppercase tracking-widest hover:bg-indigo-700 shadow-lg shadow-indigo-600/20 transition-all flex items-center space-x-2"
        >
          <i className="fas fa-plus"></i>
          <span>Nouveau Client</span>
        </button>
      </div>

      <div className="relative max-w-md">
        <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-xs"></i>
        <input 
          type="text" 
          placeholder="Rechercher un client..." 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
