                        <button onClick={() => onEditClient(client.id)} className="w-8 h-8 rounded-lg text-slate-400 hover:bg-indigo-50 dark:hover:bg-indigo-500/10 hover:text-indigo-600 transition-all" title="Modifier"><i className="fas fa-edit text-xs"></i></button>
                        <button onClick={() => onDeleteClient(client.id)} className="w-8 h-8 rounded-lg text-slate-400 hover:bg-rose-50 dark:hover:bg-rose-500/10 hover:text-rose-600 transition-all" title="Supprimer"><i className="fas fa-trash-alt text-xs"></i></button>
